/**
 * OpenAI API Provider
 * Handles GPT-4, GPT-4o, and compatible APIs
 */

import { BaseProvider } from './base-provider.js';
import { filterClaudeOnlyTools } from '../../../tools/definitions.js';

export class OpenAIProvider extends BaseProvider {
  getName() {
    return 'openai';
  }

  static matchesUrl(baseUrl) {
    return baseUrl.includes('openai.com');
  }

  getHeaders() {
    const headers = {
      'Content-Type': 'application/json',
    };

    if (this.config.apiKey) {
      headers['Authorization'] = `Bearer ${this.config.apiKey}`;
    }

    return headers;
  }

  buildUrl(_useStreaming) {
    return OpenAIProvider.normalizeChatCompletionsUrl(this.config.apiBaseUrl);
  }

  /**
   * Make a best-effort guess at the canonical chat-completions URL when the
   * user has entered a partial base URL. Handles the common shapes:
   *
   *   https://api.example.com                       → …/v1/chat/completions
   *   https://api.example.com/                      → …/v1/chat/completions
   *   https://api.example.com/v1                    → …/v1/chat/completions
   *   https://api.example.com/v1/                   → …/v1/chat/completions
   *   https://api.example.com/v1/chat/completions   → unchanged
   *   https://api.example.com/v1/completions        → unchanged (legacy)
   *   http://localhost:11434/v1                     → …/v1/chat/completions
   *
   * Leaves anything we don't recognise alone — if the user explicitly
   * pointed at a non-standard path they probably meant it.
   */
  static normalizeChatCompletionsUrl(rawUrl) {
    if (!rawUrl || typeof rawUrl !== 'string') return rawUrl;
    let url = rawUrl.trim();
    if (!url) return url;

    // Strip trailing slashes (preserve scheme).
    url = url.replace(/\/+$/, '');

    // If it already targets a completions endpoint, leave it alone.
    if (/\/(chat\/)?completions(\b|$)/.test(url)) return url;

    // If the path ends with /v1 (or a versioned segment like /v2), append
    // the standard chat-completions suffix.
    if (/\/v\d+$/.test(url)) return `${url}/chat/completions`;

    // Otherwise treat the URL as a host (or host + custom prefix) and
    // append the full /v1/chat/completions canonical path.
    return `${url}/v1/chat/completions`;
  }

  buildRequestBody(messages, systemPrompt, tools, useStreaming) {
    const convertedMessages = this._convertMessages(messages);

    // Extract text from systemPrompt array (Anthropic format)
    const systemText = Array.isArray(systemPrompt)
      ? systemPrompt.map(p => p.text).join('\n\n')
      : systemPrompt;

    const openaiMessages = [
      { role: 'system', content: systemText },
      ...convertedMessages,
    ];

    return {
      model: this.config.model,
      max_completion_tokens: this.config.maxTokens || 10000,
      messages: openaiMessages,
      tools: this._convertTools(tools),
      stream: useStreaming,
    };
  }

  normalizeResponse(response) {
    const message = response.choices?.[0]?.message;
    if (!message) {
      throw new Error(`Unexpected OpenAI response format: ${JSON.stringify(response).substring(0, 200)}`);
    }

    const content = [];
    const hadRealToolCalls = Array.isArray(message.tool_calls) && message.tool_calls.length > 0;

    // Add text content
    if (message.content) {
      content.push({ type: 'text', text: message.content });
    }

    // Add tool calls
    if (hadRealToolCalls) {
      for (const toolCall of message.tool_calls) {
        const toolUseBlock = {
          type: 'tool_use',
          id: toolCall.id,
          name: toolCall.function.name,
          input: typeof toolCall.function.arguments === 'string'
            ? JSON.parse(toolCall.function.arguments)
            : toolCall.function.arguments,
        };

        // Preserve reasoning for Kimi K2.5
        if (message.reasoning) {
          toolUseBlock.reasoning = message.reasoning;
        }
        if (message.reasoning_details) {
          toolUseBlock.reasoning_details = message.reasoning_details;
        }

        content.push(toolUseBlock);
      }
    }

    // Fallback for self-hosted servers that don't wire real tool-calling
    // through to the model. When the server returns no `tool_calls` but the
    // model writes the call as text, extract it and inject tool_use blocks
    // so the agent loop actually executes the tool. Strip the matched
    // patterns out of the rendered text so the chat doesn't show one ugly
    // raw-call bubble per round.
    let textFallbackUsed = false;
    if (!hadRealToolCalls) {
      const textBlock = content.find(b => b.type === 'text');
      const textBlob = textBlock?.text ?? '';
      const { calls, cleanedText } = OpenAIProvider.extractToolCallsFromText(textBlob);
      if (calls.length > 0) {
        textFallbackUsed = true;
        // Replace (or drop) the original text block so the bubble doesn't
        // render the raw `name: {...}` strings between tool steps.
        if (textBlock) {
          if (cleanedText && cleanedText.trim().length > 0) {
            textBlock.text = cleanedText;
          } else {
            const idx = content.indexOf(textBlock);
            if (idx >= 0) content.splice(idx, 1);
          }
        }
        for (const call of calls) {
          content.push({
            type: 'tool_use',
            id: `text_fallback_${Date.now()}_${content.length}`,
            name: call.name,
            input: call.input,
          });
        }
        // eslint-disable-next-line no-console
        console.warn(
          `[OpenAIProvider] text-fallback tool extraction: ${calls.length} call(s) recovered from model text. ` +
          `Server returned no tool_calls — likely a self-hosted endpoint that doesn't pass tools to the model.`
        );
      }
    }

    // Ensure content is never empty
    if (content.length === 0) {
      content.push({ type: 'text', text: '' });
    }

    // Map OpenAI finish_reason to Anthropic stop_reason
    let stopReason = 'end_turn';
    const finishReason = response.choices?.[0]?.finish_reason;
    if (finishReason === 'length') {
      stopReason = 'max_tokens';
    } else if (finishReason === 'tool_calls') {
      stopReason = 'tool_use';
    }
    // If we synthesised tool_use blocks from text, force stop_reason so the
    // agent loop iterates and executes them.
    if (textFallbackUsed) stopReason = 'tool_use';

    const normalized = {
      content,
      stop_reason: stopReason,
      usage: response.usage,
    };

    // Store reasoning fields at the top level for easier access
    if (message.reasoning) {
      normalized.reasoning = message.reasoning;
    }
    if (message.reasoning_details) {
      normalized.reasoning_details = message.reasoning_details;
    }

    return normalized;
  }

  async handleStreaming(response, onTextChunk, _log) {
    const reader = response.body.getReader();
    const decoder = new TextDecoder();

    let result = {
      content: [],
      usage: null,
    };

    let currentText = '';
    let toolCalls = {}; // Track by index
    let finishReason = null;
    let reasoning = null; // For Kimi K2.5
    let reasoningDetails = null; // For Kimi K2.5
    let buffer = '';

    // eslint-disable-next-line no-constant-condition
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() || '';

      for (const line of lines) {
        if (!line.startsWith('data: ')) continue;
        const data = line.slice(6);
        if (data === '[DONE]') continue;

        try {
          const chunk = JSON.parse(data);
          const choice = chunk.choices?.[0];
          if (!choice) continue;

          const delta = choice.delta;

          // Handle text content
          if (delta.content) {
            currentText += delta.content;
            if (onTextChunk) onTextChunk(delta.content);
          }

          // Handle tool calls
          if (delta.tool_calls) {
            for (const toolCall of delta.tool_calls) {
              const index = toolCall.index;

              if (!toolCalls[index]) {
                toolCalls[index] = {
                  id: toolCall.id || `call_${Date.now()}_${index}`,
                  name: toolCall.function?.name || '',
                  arguments: '',
                };
              }

              if (toolCall.function?.name) {
                toolCalls[index].name = toolCall.function.name;
              }
              if (toolCall.function?.arguments) {
                toolCalls[index].arguments += toolCall.function.arguments;
              }
            }
          }

          // Handle finish reason
          if (choice.finish_reason) {
            finishReason = choice.finish_reason;
          }

          // Handle usage (may be in final chunk)
          if (chunk.usage) {
            result.usage = chunk.usage;
          }

          // Handle reasoning for Kimi K2.5 (may be in delta or full message)
          if (delta.reasoning && !reasoning) {
            reasoning = delta.reasoning;
          }
          if (delta.reasoning_details && !reasoningDetails) {
            reasoningDetails = delta.reasoning_details;
          }
          // Also check the full message (some providers send it there)
          if (choice.message?.reasoning && !reasoning) {
            reasoning = choice.message.reasoning;
          }
          if (choice.message?.reasoning_details && !reasoningDetails) {
            reasoningDetails = choice.message.reasoning_details;
          }
        } catch (e) {
          // Ignore JSON parse errors for malformed chunks
        }
      }
    }

    // Build content array
    if (currentText) {
      result.content.push({ type: 'text', text: currentText });
    }

    // Add tool calls
    const realToolCallCount = Object.keys(toolCalls).length;
    for (const toolCall of Object.values(toolCalls)) {
      let parsedArgs = {};
      try {
        parsedArgs = JSON.parse(toolCall.arguments);
      } catch (e) {
        parsedArgs = {};
      }

      const toolUseBlock = {
        type: 'tool_use',
        id: toolCall.id,
        name: toolCall.name,
        input: parsedArgs,
      };

      // Preserve reasoning for Kimi K2.5
      if (reasoning) {
        toolUseBlock.reasoning = reasoning;
      }
      if (reasoningDetails) {
        toolUseBlock.reasoning_details = reasoningDetails;
      }

      result.content.push(toolUseBlock);
    }

    // Fallback for self-hosted servers that don't wire real tool-calling
    // through to the model: extract tool calls from the streamed text and
    // strip them so the chat doesn't render one ugly raw-call bubble per
    // round.
    let textFallbackUsed = false;
    if (realToolCallCount === 0 && currentText) {
      const { calls, cleanedText } = OpenAIProvider.extractToolCallsFromText(currentText);
      if (calls.length > 0) {
        textFallbackUsed = true;
        const textIdx = result.content.findIndex(b => b.type === 'text');
        if (textIdx >= 0) {
          if (cleanedText && cleanedText.trim().length > 0) {
            result.content[textIdx] = { type: 'text', text: cleanedText };
          } else {
            result.content.splice(textIdx, 1);
          }
        }
        for (const call of calls) {
          result.content.push({
            type: 'tool_use',
            id: `text_fallback_${Date.now()}_${result.content.length}`,
            name: call.name,
            input: call.input,
          });
        }
        // eslint-disable-next-line no-console
        console.warn(
          `[OpenAIProvider] text-fallback tool extraction (stream): ${calls.length} call(s) recovered. ` +
          `Server returned no tool_calls — likely a self-hosted endpoint that doesn't pass tools to the model.`
        );
      }
    }

    // Ensure content is never empty
    if (result.content.length === 0) {
      result.content.push({ type: 'text', text: '' });
    }

    // Map finish_reason to stop_reason
    let stopReason = 'end_turn';
    if (finishReason === 'length') {
      stopReason = 'max_tokens';
    } else if (finishReason === 'tool_calls') {
      stopReason = 'tool_use';
    }
    if (textFallbackUsed) stopReason = 'tool_use';
    result.stop_reason = stopReason;

    // Store reasoning fields at the top level for easier access (Kimi K2.5)
    if (reasoning) {
      result.reasoning = reasoning;
    }
    if (reasoningDetails) {
      result.reasoning_details = reasoningDetails;
    }

    return result;
  }

  /**
   * Convert Anthropic tools to OpenAI format
   * Filters out Claude-only tools that don't work with OpenAI models
   * @private
   */
  _convertTools(anthropicTools) {
    if (!anthropicTools || anthropicTools.length === 0) return [];

    // Filter out Claude-only tools (like turn_answer_start, update_plan)
    const filteredTools = filterClaudeOnlyTools(anthropicTools);

    return filteredTools.map(tool => ({
      type: 'function',
      function: {
        name: tool.name,
        description: tool.description,
        parameters: tool.input_schema,
      },
    }));
  }

  /**
   * Convert Anthropic messages to OpenAI format
   * @private
   */
  _convertMessages(anthropicMessages) {
    const openaiMessages = [];

    for (const msg of anthropicMessages) {
      // Simple string content - keep as is
      if (typeof msg.content === 'string') {
        openaiMessages.push({
          role: msg.role,
          content: msg.content,
        });
        continue;
      }

      // Array content - need to convert blocks
      if (Array.isArray(msg.content)) {
        if (msg.role === 'assistant') {
          // Assistant message with content blocks
          let textContent = '';
          const toolCalls = [];
          let reasoning = null;
          let reasoningDetails = null;

          for (const block of msg.content) {
            if (block.type === 'text') {
              textContent += block.text;
            } else if (block.type === 'tool_use') {
              toolCalls.push({
                id: block.id,
                type: 'function',
                function: {
                  name: block.name,
                  arguments: JSON.stringify(block.input),
                },
              });

              // Preserve reasoning fields for Kimi K2.5
              if (block.reasoning && !reasoning) {
                reasoning = block.reasoning;
              }
              if (block.reasoning_details && !reasoningDetails) {
                reasoningDetails = block.reasoning_details;
              }
            }
          }

          const assistantMsg = {
            role: 'assistant',
            content: textContent || null,
          };
          if (toolCalls.length > 0) {
            assistantMsg.tool_calls = toolCalls;
          }

          // Include reasoning fields for Kimi K2.5 if present
          // Kimi RETURNS "reasoning" but EXPECTS "reasoning_content" when sending back
          if (reasoning) {
            assistantMsg.reasoning_content = reasoning;
          }
          if (reasoningDetails) {
            assistantMsg.reasoning_details = reasoningDetails;
          }

          openaiMessages.push(assistantMsg);

        } else if (msg.role === 'user') {
          // User message with tool results
          for (const block of msg.content) {
            if (block.type === 'tool_result') {
              // OpenAI expects role: 'tool' with tool_call_id
              let content = '';
              if (typeof block.content === 'string') {
                content = block.content;
              } else if (Array.isArray(block.content)) {
                // Handle array content (e.g., text + image)
                content = block.content
                  .filter(c => c.type === 'text')
                  .map(c => c.text)
                  .join('\n');
              }

              openaiMessages.push({
                role: 'tool',
                tool_call_id: block.tool_use_id,
                content: content,
              });
            } else if (block.type === 'text') {
              // Regular text in user message
              openaiMessages.push({
                role: 'user',
                content: block.text,
              });
            }
          }
        }
      }
    }

    return openaiMessages;
  }

  /**
   * Recover tool calls from raw model text. Used when the server returns
   * no `tool_calls` array but the model has written what it would call as
   * plain text (common with self-hosted OpenAI-compatible servers that
   * accept the `tools` field but don't actually wire tool-calling into the
   * model).
   *
   * Recognises:
   *   1.  ```json … ``` / ```tool_call … ``` fenced JSON blocks shaped
   *       either as { "name": "…", "arguments": { … } } or
   *       { "function": { "name": "…", "arguments": "{…}" } }
   *   2.  tool_name({ "k": "v" }) inline function-call syntax
   *   3.  tool_name: { "k": "v" } key-value style
   *
   * Returns { calls, cleanedText }:
   *   calls       — array of { name, input } objects extracted
   *   cleanedText — the original text with each matched tool-call pattern
   *                 sliced out, so callers can suppress the noisy raw text
   *                 from the chat (rendering only the structured step row).
   * Never throws.
   */
  static extractToolCallsFromText(text) {
    if (!text || typeof text !== 'string') {
      return { calls: [], cleanedText: text ?? '' };
    }
    const out = [];
    const seen = new Set();
    // Spans of the source text we'll remove from the rendered version.
    // [startInclusive, endExclusive] pairs in source-text indices.
    const cuts = [];
    const push = (name, input, span) => {
      if (!name || typeof name !== 'string') return;
      const key = `${name}:${JSON.stringify(input ?? null)}`;
      if (seen.has(key)) return;
      seen.add(key);
      out.push({ name, input: input ?? {} });
      if (span) cuts.push(span);
    };

    // --- Pattern 1: fenced JSON blocks ---
    const fenceRe = /```(?:json|tool_use|tool_call|function|xml)?\s*\n?([\s\S]*?)```/g;
    let m;
    while ((m = fenceRe.exec(text)) !== null) {
      const body = m[1].trim();
      if (!body || body[0] !== '{') continue;
      try {
        const obj = JSON.parse(body);
        const matchStart = m.index;
        const matchEnd = m.index + m[0].length;
        if (obj?.function?.name) {
          const args = typeof obj.function.arguments === 'string'
            ? JSON.parse(obj.function.arguments)
            : obj.function.arguments;
          push(obj.function.name, args, [matchStart, matchEnd]);
        } else if (typeof obj?.name === 'string') {
          const rawArgs = obj.arguments ?? obj.input ?? obj.parameters ?? {};
          const args = typeof rawArgs === 'string' ? JSON.parse(rawArgs) : rawArgs;
          push(obj.name, args, [matchStart, matchEnd]);
        }
      } catch {
        /* not JSON — fall through to inline scan */
      }
    }

    // --- Pattern 2: inline tool_name({ … }) and tool_name: { … } ---
    // Some models emit `navigate({"url": "…"})` (function-call style) and
    // others emit `navigate: {"url": "…"}` (key-value style). Match both.
    // Exclude leading `.` (method call), `"` (JSON key), and word chars.
    const KEYWORDS = new Set([
      'if','for','while','return','function','const','let','var','await',
      'async','try','catch','throw','new','this','class','import','export',
      'typeof','instanceof','do','switch','case','console','log','parse',
      'stringify','print','format','setTimeout','setInterval','clearTimeout',
      'clearInterval','Math','Object','Array','String','Number','Boolean',
      'true','false','null','undefined'
    ]);
    const idRe = /(?:^|[^."\w])([a-z_][a-z_0-9]{2,})\s*(?:\(\s*|:\s*)\{/gi;
    while ((m = idRe.exec(text)) !== null) {
      const name = m[1];
      if (KEYWORDS.has(name)) continue;

      // m.index points BEFORE the leading boundary char (when one matched).
      // Find the real start of the identifier so we can cut cleanly.
      const idStart = text.indexOf(name, m.index);
      const openBraceIdx = m.index + m[0].length - 1;
      let depth = 1;
      let i = openBraceIdx + 1;
      let inString = null;
      while (i < text.length && depth > 0) {
        const ch = text[i];
        if (inString) {
          if (ch === '\\') { i += 2; continue; }
          if (ch === inString) inString = null;
        } else if (ch === '"' || ch === "'") {
          inString = ch;
        } else if (ch === '{') {
          depth += 1;
        } else if (ch === '}') {
          depth -= 1;
        }
        i += 1;
      }
      if (depth !== 0) continue;

      // If the call was paren-style, swallow the trailing `)` too.
      let endIdx = i;
      while (endIdx < text.length && /\s/.test(text[endIdx])) endIdx += 1;
      if (text[endIdx] === ')') endIdx += 1;

      const jsonText = text.slice(openBraceIdx, i);
      try {
        push(name, JSON.parse(jsonText), [idStart >= 0 ? idStart : m.index, endIdx]);
      } catch {
        // Light repair attempt: single-quoted JSON
        try {
          push(
            name,
            JSON.parse(jsonText.replace(/'/g, '"')),
            [idStart >= 0 ? idStart : m.index, endIdx]
          );
        } catch {
          /* give up on this match */
        }
      }
    }

    // Build cleanedText by removing all the matched spans (descending order
    // so earlier indices stay valid as we splice). Collapse runs of blank
    // lines left behind.
    let cleanedText = text;
    cuts.sort((a, b) => b[0] - a[0]);
    for (const [s, e] of cuts) {
      cleanedText = cleanedText.slice(0, s) + cleanedText.slice(e);
    }
    cleanedText = cleanedText
      .replace(/[ \t]+\n/g, '\n')        // strip trailing spaces on lines
      .replace(/\n{3,}/g, '\n\n')        // collapse 3+ newlines → 2
      .replace(/^\s+|\s+$/g, '');        // trim outer whitespace

    return { calls: out, cleanedText };
  }
}
