/**
 * Nugget key computation — κ = (s_norm, p, scope).
 *
 * Implements paper §3.3 stage 2: canonicalization + keying. Excludes the
 * object value so different values under the same key surface as conflicts.
 *
 * See ADR 0005 and:
 *   "NuggetIndex: Governed Atomic Retrieval for Maintainable RAG"
 *   https://arxiv.org/html/2604.27306v1
 */

/**
 * Normalize a subject for keying. Lowercases, trims, collapses whitespace.
 * Domain-specific alias resolution (e.g., "USA" → "United States") is the
 * caller's responsibility — they pass in already-canonicalized strings when
 * they have stronger normalization available.
 */
export function normalizeSubject(subject) {
  return String(subject).toLowerCase().trim().replace(/\s+/g, " ");
}

/**
 * Compute κ = (s_norm, p, scope). Returned as a stable string for use as a
 * dictionary/index key. Excludes object value by design (paper §3.3.2).
 */
export function computeKey({ fact, validity }) {
  return `${normalizeSubject(fact.subject)}�${fact.predicate}�${validity.scope}`;
}

/**
 * Stable nugget ID — hashes the full record minus the ID itself.
 * Two records with the same (key, value, validity window, scope) collide,
 * which is the desired behavior for idempotent insertion.
 */
export function computeNuggetId({ fact, validity }) {
  const seed = JSON.stringify([
    normalizeSubject(fact.subject),
    fact.predicate,
    fact.object,
    validity.scope,
    validity.start,
    validity.end ?? "∞",
  ]);
  return fnv1a(seed);
}

/**
 * FNV-1a 64-bit hash — cheap, deterministic, sync. Not crypto-grade; IDs are
 * idempotency keys, not security tokens. 64 bits ≈ 2^32 records before 50%
 * birthday collision risk, which is comfortably beyond any local memory store.
 *
 * 32-bit FNV-1a collides at ~50K records (we observed this during the Phase 3
 * storage spike). 64-bit eliminates the problem without needing Web Crypto's
 * async surface.
 */
function fnv1a(input) {
  let hash = 0xcbf29ce484222325n;
  const PRIME = 0x100000001b3n;
  for (let i = 0; i < input.length; i++) {
    hash ^= BigInt(input.charCodeAt(i));
    hash = (hash * PRIME) & 0xffffffffffffffffn;
  }
  return hash.toString(16).padStart(16, "0");
}
