/**
 * Browser-side collector for cross-tab context (8.9).
 *
 * Calls `browser.tabs.query()` and runs the result through the pure filter
 * from `@browser-memex/core/tab-context`. Reads the user's blocked-hosts
 * setting from the active profile (or chrome.storage if no profile system
 * is wired in this build).
 */

import browser from "webextension-polyfill";
import { filterTabs } from "@browser-memex/core/tab-context";

const PRIVACY_KEY = "browser-memex.privacy";

/**
 * Collect a sanitized snapshot of the user's open tabs.
 *
 * @param {object} [opts]
 * @param {boolean} [opts.includeIncognito=false]
 * @param {number} [opts.maxTabs=50]
 * @param {string[]} [opts.blockedHosts]
 *   Overrides the privacy-setting list. If omitted, reads from
 *   chrome.storage.local under PRIVACY_KEY.
 */
export async function collectTabContext(opts = {}) {
  const rawTabs = await browser.tabs.query({});
  let blockedHosts = opts.blockedHosts;
  if (blockedHosts === undefined) {
    const data = await browser.storage.local.get([PRIVACY_KEY]);
    blockedHosts = data?.[PRIVACY_KEY]?.disabledDomains ?? [];
  }
  return filterTabs(rawTabs, {
    includeIncognito: opts.includeIncognito ?? false,
    blockedHosts,
    maxTabs: opts.maxTabs ?? 50,
  });
}
