/**
 * Browser data tool handlers
 * Handles: search_history, create_bookmark, search_bookmarks, delete_bookmark
 */

/**
 * Find the "Other Bookmarks" / unfiled root folder across browsers.
 * Chrome uses id "2", Firefox uses "unfiled_____".
 */
async function getUnfiledRootId() {
  const tree = await chrome.bookmarks.getTree();
  const root = tree[0];
  // Look for unfiled/Other Bookmarks node among root children
  for (const child of root.children || []) {
    if (child.id === 'unfiled_____' || child.id === '2') return child.id;
    if (/unfiled|other bookmarks/i.test(child.title) && !child.url) return child.id;
  }
  // Fallback: last root child (typically Other Bookmarks)
  const children = root.children || [];
  return children.length > 0 ? children[children.length - 1].id : root.id;
}

/**
 * Search browsing history by keyword and time range.
 */
export async function handleSearchHistory(toolInput, deps) {
  const query = toolInput.query || '';
  const maxResults = toolInput.max_results || 20;
  const daysBack = toolInput.days_back || 30;
  const startTime = Date.now() - daysBack * 24 * 60 * 60 * 1000;

  try {
    const results = await chrome.history.search({ text: query, startTime, maxResults });

    if (results.length === 0) {
      return `No history found${query ? ` matching "${query}"` : ''} in the last ${daysBack} days.`;
    }

    const items = results.map(item => ({
      url: item.url,
      title: item.title || '(no title)',
      lastVisitTime: new Date(item.lastVisitTime).toISOString(),
      visitCount: item.visitCount,
    }));

    return JSON.stringify({ count: items.length, query: query || '(all recent)', daysBack, results: items }, null, 2);
  } catch (err) {
    return `Error searching history: ${err.message}`;
  }
}

/**
 * Create a bookmark. Defaults to current active tab if no URL provided.
 */
export async function handleCreateBookmark(toolInput, deps) {
  let { url, title, folder } = toolInput;

  if (!url) {
    try {
      const [activeTab] = await chrome.tabs.query({ active: true, currentWindow: true });
      if (activeTab) {
        url = activeTab.url;
        if (!title) title = activeTab.title;
      } else {
        return 'Error: No URL provided and no active tab found.';
      }
    } catch (err) {
      return `Error getting active tab: ${err.message}`;
    }
  }

  try {
    let parentId = await getUnfiledRootId();

    if (folder) {
      const existing = await chrome.bookmarks.search({ title: folder });
      const match = existing.find(n => !n.url && n.title === folder);
      if (match) {
        parentId = match.id;
      } else {
        const created = await chrome.bookmarks.create({ parentId, title: folder });
        parentId = created.id;
      }
    }

    const bookmark = await chrome.bookmarks.create({ parentId, title: title || url, url });
    return `Bookmarked "${bookmark.title}" (${url}) in folder "${folder || 'Other Bookmarks'}".`;
  } catch (err) {
    return `Error creating bookmark: ${err.message}`;
  }
}

/**
 * Search saved bookmarks by keyword.
 */
export async function handleSearchBookmarks(toolInput, deps) {
  const { query } = toolInput;
  if (!query) return 'Error: query is required for searching bookmarks.';

  try {
    const results = await chrome.bookmarks.search(query);
    const bookmarks = results.filter(n => n.url);

    if (bookmarks.length === 0) {
      return `No bookmarks found matching "${query}".`;
    }

    const items = await Promise.all(bookmarks.slice(0, 30).map(async (node) => {
      let folderName = 'Bookmarks';
      if (node.parentId) {
        try {
          const [parent] = await chrome.bookmarks.get(node.parentId);
          folderName = parent.title || 'Bookmarks';
        } catch { /* ignore */ }
      }
      return {
        url: node.url,
        title: node.title || '(no title)',
        dateAdded: node.dateAdded ? new Date(node.dateAdded).toISOString() : null,
        folder: folderName,
      };
    }));

    return JSON.stringify({ count: items.length, query, results: items }, null, 2);
  } catch (err) {
    return `Error searching bookmarks: ${err.message}`;
  }
}

/**
 * Remove a bookmark by URL. Removes all matches.
 */
export async function handleDeleteBookmark(toolInput, deps) {
  const { url } = toolInput;
  if (!url) return 'Error: url is required.';

  try {
    const results = await chrome.bookmarks.search({ url });
    if (results.length === 0) {
      return `No bookmark found for URL: ${url}`;
    }

    let removed = 0;
    for (const node of results) {
      if (node.url) {
        await chrome.bookmarks.remove(node.id);
        removed++;
      }
    }
    return `Removed ${removed} bookmark(s) for ${url}.`;
  } catch (err) {
    return `Error deleting bookmark: ${err.message}`;
  }
}
