/**
 * availability-snapshot.js — produces the Router's Availability object from
 * runtime state.
 *
 * In the service worker context we can't `fs.access` the user's filesystem,
 * so we delegate detection to the MCP server (which DOES have filesystem
 * access). The service worker requests a detection snapshot over the MCP
 * bridge and caches it for `cacheTtlMs`.
 *
 * Fallback when MCP isn't reachable: assume nothing is available. The
 * Router will then route everything to the default fallback agent if it's
 * in `installed`, or to NO_AGENT_AVAILABLE otherwise.
 */

const DEFAULT_TTL_MS = 5 * 60 * 1000; // 5 min

export class AvailabilitySnapshot {
  /**
   * @param {object} opts
   * @param {() => Promise<{ installed: string[], configured: string[] }>} opts.fetchFromMcp
   * @param {() => Promise<object>} [opts.fetchHistorySignals]
   *                                  — optional: returns
   *                                    { recentSuccessRate, recentCostUsd, recentLatencyMs }
   *                                    aggregated from TaskStore.runs across recent tasks
   * @param {number} [opts.cacheTtlMs=300000]
   */
  constructor({ fetchFromMcp, fetchHistorySignals, cacheTtlMs = DEFAULT_TTL_MS }) {
    if (typeof fetchFromMcp !== "function") {
      throw new Error("AvailabilitySnapshot: fetchFromMcp required");
    }
    this.fetchFromMcp = fetchFromMcp;
    this.fetchHistorySignals = fetchHistorySignals ?? null;
    this.cacheTtlMs = cacheTtlMs;
    this.cached = null;
    this.cachedAt = 0;
  }

  /**
   * Get the current snapshot. Returns cached if within TTL.
   */
  async get(nowMs = Date.now()) {
    if (this.cached && nowMs - this.cachedAt < this.cacheTtlMs) {
      return this.cached;
    }

    let installed = [];
    let configured = [];
    try {
      const det = await this.fetchFromMcp();
      installed = Array.isArray(det?.installed) ? det.installed : [];
      configured = Array.isArray(det?.configured) ? det.configured : [];
    } catch {
      // MCP unreachable; degrade gracefully
    }

    let history = {};
    if (this.fetchHistorySignals) {
      try {
        history = (await this.fetchHistorySignals()) ?? {};
      } catch {
        history = {};
      }
    }

    this.cached = {
      installed,
      configured,
      recentSuccessRate: history.recentSuccessRate ?? {},
      recentCostUsd: history.recentCostUsd ?? {},
      recentLatencyMs: history.recentLatencyMs ?? {},
    };
    this.cachedAt = nowMs;
    return this.cached;
  }

  /** Force the next get() to re-fetch. */
  invalidate() {
    this.cachedAt = 0;
  }
}
