/**
 * agent-dispatcher.js — bridges Scheduler's TaskDispatcher interface to the
 * extension's existing browser-agent machinery.
 *
 * The Scheduler doesn't know how to drive a browser tab. It calls
 * `dispatch(task, ctx)` and expects a RunResult. This module provides that
 * implementation by:
 *
 *   1. Translating Scheduler `task.payload` into the existing browser-agent
 *      task spec (the same one `service-worker.js` already runs)
 *   2. Opening / reusing a tab, dispatching the task, awaiting completion
 *   3. Returning the result in the Scheduler's RunResult shape, populating
 *      `cost` and `routing` from the run's outcome
 *
 * The actual browser-agent execution lives in `service-worker.js`. We don't
 * duplicate it — we call the existing entry points.
 */

import { Router } from "@browser-memex/core/router";

/**
 * @typedef {Object} AgentDispatcherDeps
 * @property {() => Promise<object>} availability  — produces Router availability snapshot
 * @property {object} policy                       — routing policy
 * @property {(task: object) => Promise<object>} runBrowserAgent
 *                                                 — invokes the existing service-worker
 *                                                   agent loop for one task; returns
 *                                                   { success, result, cost?, error? }
 */

export class AgentDispatcher {
  /**
   * @param {AgentDispatcherDeps} deps
   * @param {object} [opts]
   * @param {object} [opts.llmClient]              — optional LLM fallback client
   */
  constructor(deps, opts = {}) {
    if (!deps || typeof deps.availability !== "function") {
      throw new Error("AgentDispatcher: deps.availability is required");
    }
    if (typeof deps.runBrowserAgent !== "function") {
      throw new Error("AgentDispatcher: deps.runBrowserAgent is required");
    }
    if (!deps.policy) {
      throw new Error("AgentDispatcher: deps.policy is required");
    }
    this.deps = deps;
    this.router = new Router({ policy: deps.policy, llmClient: opts.llmClient });
  }

  /**
   * Scheduler-facing dispatch entry point.
   */
  async dispatch(task, ctx) {
    const availability = await this.deps.availability();
    const decision = await this.router.route(task, availability, ctx);

    if (!decision.chosenAgentId) {
      return {
        success: false,
        error: `No agent available: ${decision.explanation}`,
        routing: decision,
      };
    }

    // Pin the chosen agent for this run via task.routing.agentId so the
    // existing browser-agent machinery knows which one to invoke.
    const taskForAgent = {
      ...task,
      routing: { ...(task.routing ?? {}), agentId: decision.chosenAgentId },
    };

    try {
      const outcome = await this.deps.runBrowserAgent(taskForAgent);
      return {
        success: Boolean(outcome?.success),
        result: outcome?.result,
        error: outcome?.error,
        // WATCHER / TRACKER pass-through
        sample: outcome?.sample,
        extractedValue: outcome?.extractedValue,
        extractedText: outcome?.extractedText,
        // Cost may be populated by the agent provider; otherwise leave undefined
        cost: outcome?.cost,
        // Always attach the routing decision so task_runs records "why this agent"
        routing: decision,
      };
    } catch (err) {
      return {
        success: false,
        error: err?.message ?? String(err),
        routing: decision,
      };
    }
  }
}
