/**
 * services-rpc.js — message-channel router for side-panel ↔ service-worker
 * calls into the core services.
 *
 * Side panel sends `{ type: 'services.<op>', args }`. This handler routes
 * to the live service instances from extension-services.js.
 *
 * Returns `{ ok: true, result }` or `{ ok: false, error, notReady? }`.
 *
 * All data RPCs (tasks/memory/skills) auto-inject the active profile id from
 * extension-services so the side panel never has to thread it through.
 * Profile RPCs go through the lighter `bootProfiles()` path so they work even
 * if the full SQLite boot hasn't finished.
 */

import browser from "webextension-polyfill";
import {
  services,
  bootServices,
  bootProfiles,
  isBooted,
  isProfilesBooted,
  activeProfileId,
  setActiveProfile,
  runSkill,
} from "./modules/extension-services.js";
import { collectTabContext } from "./modules/tab-context.js";

/**
 * Helper: pull the live ProfileStore from whichever boot stage is reached.
 * Falls back to bootProfiles() (which is cheap and always works).
 */
async function profileStore() {
  if (isBooted()) return services().profileStore;
  const { profileStore: ps } = await bootProfiles();
  return ps;
}

const handlers = {
  // ----- tasks (scoped by active profile) -----
  "services.tasks.list": async (args) =>
    services().taskStore.list({ ...(args ?? {}), profileId: activeProfileId() }),
  "services.tasks.get": async ({ id }) => services().taskStore.get(id),
  "services.tasks.create": async (spec) =>
    services().taskStore.create(spec, Date.now(), activeProfileId()),
  "services.tasks.cancel": async ({ id }) => services().taskStore.cancel(id, Date.now()),
  "services.tasks.pause": async ({ id }) => services().taskStore.pause(id, Date.now()),
  "services.tasks.resume": async ({ id }) => services().taskStore.resume(id, Date.now()),
  "services.tasks.runs": async ({ id, limit }) => services().taskStore.runs(id, limit),
  "services.tasks.trackerSamples": async ({ id, limit }) =>
    services().taskStore.trackerSamples(id, limit),

  // ----- memory (scoped by active profile) -----
  "services.memory.query": async ({ text, options }) =>
    services().nuggetStore.query(text, {
      ...(options ?? {}),
      profileId: activeProfileId(),
    }),
  "services.memory.get": async ({ id }) => services().nuggetStore.get(id),
  "services.memory.count": async () => services().nuggetStore.count(activeProfileId()),
  "services.memory.provenance": async ({ id }) => services().nuggetStore.provenance(id),
  "services.memory.promote": async ({ id, tier }) => services().nuggetStore.promote(id, tier),

  // ----- skills (scoped by active profile) -----
  "services.skills.list": async (args) =>
    services().skillStore.list({ ...(args ?? {}), profileId: activeProfileId() }),
  "services.skills.get": async ({ id }) => services().skillStore.get(id),
  "services.skills.getByName": async ({ name }) =>
    services().skillStore.getByName(name, activeProfileId()),
  "services.skills.create": async (spec) =>
    services().skillStore.create(spec, Date.now(), activeProfileId()),
  "services.skills.update": async ({ id, patch }) =>
    services().skillStore.update(id, patch, Date.now()),
  "services.skills.archive": async ({ id }) => services().skillStore.archive(id, Date.now()),
  "services.skills.delete": async ({ id }) => services().skillStore.delete(id),
  "services.skills.runs": async ({ id, limit }) => services().skillStore.runs(id, limit),
  "services.skills.run": async ({ id, inputs }) => runSkill(id, inputs ?? {}),
  "services.skills.export": async ({ id }) => services().skillStore.exportSkill(id),
  "services.skills.import": async ({ envelope }) =>
    services().skillStore.importEnvelope(envelope, Date.now(), activeProfileId()),

  // Skill self-teaching: turn one recorded successful run into a saved skill.
  "services.skills.proposeFromTrajectory": async ({ trajectory }) => {
    const { proposeSkillFromTrajectory } = await import("@browser-memex/core/skills");
    return proposeSkillFromTrajectory(trajectory);
  },
  "services.skills.confirmProposal": async ({ proposal, name, description }) => {
    return services().skillStore.confirmFromProposal(
      proposal,
      Date.now(),
      { name, description }
    );
  },

  // ----- agents -----
  "services.agents.availability": async () => services().availability.get(),
  "services.agents.invalidateAvailability": async () => {
    services().availability.invalidate();
    return { ok: true };
  },

  // ----- tab context -----
  "services.tabContext.collect": async (opts) => collectTabContext(opts ?? {}),

  // ----- profiles (lightweight; available pre-full-boot) -----
  "services.profiles.list": async () => (await profileStore()).list(),
  "services.profiles.get": async ({ id }) => (await profileStore()).get(id),
  "services.profiles.getActive": async () => {
    const ps = await profileStore();
    return ps.getActive(Date.now());
  },
  "services.profiles.setActive": async ({ id }) => {
    await setActiveProfile(id);
    return { id };
  },
  "services.profiles.create": async (spec) => {
    const ps = await profileStore();
    return ps.create(spec, Date.now());
  },
  "services.profiles.update": async ({ id, patch }) => {
    const ps = await profileStore();
    return ps.update(id, patch, Date.now());
  },
  "services.profiles.delete": async ({ id }) => (await profileStore()).delete(id),
  "services.profiles.duplicate": async ({ id, newName }) => {
    const ps = await profileStore();
    return ps.duplicate(id, newName, Date.now());
  },

  // ----- diagnostics -----
  "services.health": async () => ({
    booted: isBooted(),
    profilesBooted: isProfilesBooted(),
    bootError: getBootError(),
    vfs: isBooted() ? services().vfs : null,
    activeProfileId: activeProfileId(),
  }),
};

const PROFILE_HANDLERS = new Set([
  "services.profiles.list",
  "services.profiles.get",
  "services.profiles.getActive",
  "services.profiles.setActive",
  "services.profiles.create",
  "services.profiles.update",
  "services.profiles.delete",
  "services.profiles.duplicate",
  "services.health",
]);

let _bootError = null;

export function setBootError(err) {
  _bootError = err ? String(err?.message ?? err) : null;
}

function getBootError() {
  return _bootError;
}

let _installed = false;

/**
 * Install the RPC handler. Idempotent.
 *
 * IMPORTANT: This must be called *before* bootServices() so the listener is
 * registered even if boot fails. Without an installed listener, browsers
 * reject the message with "Could not establish connection. Receiving end
 * does not exist." — leaving the side-panel UI stuck on loading spinners.
 */
export function installServicesRpc() {
  if (_installed) return;
  _installed = true;

  browser.runtime.onMessage.addListener((message, _sender) => {
    if (!message || typeof message.type !== "string") return false;
    const handler = handlers[message.type];
    if (!handler) return false;
    return (async () => {
      try {
        // Profile RPCs + health don't require full SQLite boot.
        if (!PROFILE_HANDLERS.has(message.type) && !isBooted()) {
          const detail = getBootError()
            ? `services unavailable: ${getBootError()}`
            : "services initializing, please retry";
          return { ok: false, error: detail, notReady: true };
        }
        const result = await handler(message.args ?? {});
        return { ok: true, result };
      } catch (e) {
        return { ok: false, error: e?.message ?? String(e) };
      }
    })();
  });
}

/** Optional helper for diagnostics — list the RPC methods this build supports. */
export function rpcMethods() {
  return Object.keys(handlers);
}

// Re-export for the side-panel side
export { bootServices };
