/**
 * IndexedDB wrapper for task memory persistence.
 * Stores task outcomes and auto-generated domain skills.
 */

const DB_NAME = 'browser-memex-task-memory';
const DB_VERSION = 1;
const TASK_HISTORY = 'taskHistory';
const LEARNED_SKILLS = 'learnedSkills';

let dbPromise = null;

export function openDB() {
  if (!dbPromise) {
    dbPromise = new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);
      request.onupgradeneeded = (event) => {
        const db = event.target.result;
        if (!db.objectStoreNames.contains(TASK_HISTORY)) {
          const store = db.createObjectStore(TASK_HISTORY, {
            keyPath: 'id',
            autoIncrement: true,
          });
          store.createIndex('domain', 'domain', { unique: false });
          store.createIndex('createdAt', 'createdAt', { unique: false });
          store.createIndex('status', 'status', { unique: false });
        }
        if (!db.objectStoreNames.contains(LEARNED_SKILLS)) {
          db.createObjectStore(LEARNED_SKILLS, { keyPath: 'domain' });
        }
      };
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => {
        dbPromise = null;
        reject(request.error);
      };
    });
  }
  return dbPromise;
}

function txStore(storeName, mode = 'readonly') {
  return openDB().then(db => {
    const tx = db.transaction(storeName, mode);
    return tx.objectStore(storeName);
  });
}

export async function addTaskRecord(record) {
  const store = await txStore(TASK_HISTORY, 'readwrite');
  return new Promise((resolve, reject) => {
    const req = store.add(record);
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

export async function getTasksByDomain(domain, limit = 10) {
  const store = await txStore(TASK_HISTORY);
  return new Promise((resolve, reject) => {
    const index = store.index('domain');
    const results = [];
    const req = index.openCursor(IDBKeyRange.only(domain), 'prev');
    req.onsuccess = (event) => {
      const cursor = event.target.result;
      if (cursor && results.length < limit) {
        results.push(cursor.value);
        cursor.continue();
      } else {
        resolve(results);
      }
    };
    req.onerror = () => reject(req.error);
  });
}

