export async function getMemoryStats() {
  const db = await openDB();
  const tx = db.transaction([TASK_HISTORY, LEARNED_SKILLS], 'readonly');

  const taskCount = await new Promise((resolve, reject) => {
    const req = tx.objectStore(TASK_HISTORY).count();
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  // Count unique domains
  const domains = new Set();
  await new Promise((resolve, reject) => {
    const index = tx.objectStore(TASK_HISTORY).index('domain');
    const req = index.openKeyCursor();
    req.onsuccess = (event) => {
      const cursor = event.target.result;
      if (cursor) {
        domains.add(cursor.key);
        cursor.continue();
      } else {
        resolve();
      }
    };
    req.onerror = () => reject(req.error);
  });

  const skillCount = await new Promise((resolve, reject) => {
    const req = tx.objectStore(LEARNED_SKILLS).count();
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });

  return {
    totalTasks: taskCount,
    totalDomains: domains.size,
    learnedSkillCount: skillCount,
  };
}

export async function pruneOldRecords(maxAgeDays = 90) {
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - maxAgeDays);
  const cutoffStr = cutoff.toISOString();

  const store = await txStore(TASK_HISTORY, 'readwrite');
  return new Promise((resolve, reject) => {
    const index = store.index('createdAt');
    const range = IDBKeyRange.upperBound(cutoffStr);
    const req = index.openCursor(range);
    let deleted = 0;
    req.onsuccess = (event) => {
      const cursor = event.target.result;
      if (cursor) {
        cursor.delete();
        deleted++;
        cursor.continue();
      } else {
        resolve(deleted);
      }
    };
    req.onerror = () => reject(req.error);
  });
}
