/**
 * extension-bootstrap.js — initializes the core services and RPC surface
 * inside the service worker.
 *
 * Boot order matters:
 *
 *   1. installServicesRpc()  — synchronous; registers the message-channel
 *      listener BEFORE any side-panel page can open. Without this,
 *      Firefox/Chrome reject side-panel RPC calls with "Could not establish
 *      connection. Receiving end does not exist."
 *
 *   2. bootProfiles()        — async but cheap (chrome.storage only).
 *      Always succeeds. Surface the active profile to the rail-avatar so the
 *      UI is never stuck on "Loading profiles…" when the heavier SQLite boot
 *      is slow or fails.
 *
 *   3. bootServices()        — async, may fail (WASM CSP, OPFS unavailable,
 *      …). Tries OPFS-SAHPool first, falls back to in-memory SQLite so the UI
 *      still works on Firefox event-page backgrounds.
 *
 * Failures in step 3 are recorded for the `services.health` diagnostic RPC;
 * profile/skills/tasks/memory RPCs return `{ ok:false, notReady:true }` until
 * a successful boot.
 */

import browser from "webextension-polyfill";
import { bootProfiles, bootServices } from "./modules/extension-services.js";
import { installServicesRpc, setBootError } from "./services-rpc.js";

const POLICY_KEY = "browser-memex.policy";
const PROFILES_KEY = "browser-memex.profiles";
const ACTIVE_PROFILE_KEY = "browser-memex.activeProfileId";

const DEFAULT_POLICY = Object.freeze({
  rules: [],
  fallback: "claude-code",
  overrides: [],
  llmFallbackEnabled: false,
});

let booted = false;

export async function startExtensionServices({ runBrowserAgent, fetchAgentDetection } = {}) {
  if (booted) return;

  installServicesRpc();

  // Step 2: profiles first — light, always works.
  try {
    await bootProfiles();
    // eslint-disable-next-line no-console
    console.log("[browser-memex] profiles ready");
  } catch (err) {
    // eslint-disable-next-line no-console
    console.error("[browser-memex] bootProfiles failed:", err);
    // Continue — RPCs for profiles will return notReady; SQLite boot may still try.
  }

  const policy = await resolveActivePolicy().catch(() => DEFAULT_POLICY);
  const bootOpts = {
    policy,
    fetchAgentDetection: fetchAgentDetection ?? defaultFetchAgentDetection,
    runBrowserAgent: runBrowserAgent ?? defaultRunBrowserAgent,
  };

  const tryBoot = async (vfs) => {
    await bootServices({ ...bootOpts, vfs });
  };

  try {
    await tryBoot("opfs-sahpool");
    booted = true;
    setBootError(null);
    // eslint-disable-next-line no-console
    console.log("[browser-memex] core services ready (opfs-sahpool)");
    return;
  } catch (err) {
    // eslint-disable-next-line no-console
    console.warn(
      "[browser-memex] opfs-sahpool unavailable, falling back to in-memory SQLite:",
      err?.message ?? err
    );
  }

  try {
    await tryBoot("memory");
    booted = true;
    setBootError(null);
    // eslint-disable-next-line no-console
    console.log(
      "[browser-memex] core services ready (in-memory; data will not persist across restarts)"
    );
  } catch (err) {
    setBootError(err);
    // eslint-disable-next-line no-console
    console.error("[browser-memex] bootServices failed (both VFS attempts):", err);
  }
}

/**
 * Resolve the routing policy from the active profile, with fallback to the
 * standalone `browser-memex.policy` key (for users who haven't switched to
 * profiles yet) or a built-in default.
 */
async function resolveActivePolicy() {
  const data = await browser.storage.local.get([POLICY_KEY, PROFILES_KEY, ACTIVE_PROFILE_KEY]);
  const profiles = Array.isArray(data?.[PROFILES_KEY]) ? data[PROFILES_KEY] : [];
  const activeId = data?.[ACTIVE_PROFILE_KEY];
  const active = profiles.find((p) => p.id === activeId);
  if (active?.policy) return active.policy;
  if (data?.[POLICY_KEY]) return data[POLICY_KEY];
  return DEFAULT_POLICY;
}

async function defaultFetchAgentDetection() {
  try {
    const { detectAgentsViaMcp } = await import("./modules/mcp-bridge.js").catch(() => ({}));
    if (typeof detectAgentsViaMcp === "function") {
      return await detectAgentsViaMcp();
    }
  } catch {
    /* fall through */
  }
  return { installed: [], configured: [] };
}

async function defaultRunBrowserAgent(task) {
  return new Promise((resolve) => {
    const onResponse = (response) => {
      if (browser.runtime.lastError) {
        resolve({ success: false, error: browser.runtime.lastError.message });
        return;
      }
      resolve(response ?? { success: false, error: "no response from agent loop" });
    };
    try {
      browser.runtime.sendMessage(
        { type: "scheduler.runTask", task },
        onResponse
      );
    } catch (e) {
      resolve({ success: false, error: e?.message ?? String(e) });
    }
  });
}
