/**
 * Algorithm 2 — Conflict Detection and State Assignment.
 *
 * Implements paper §3.3.2 verbatim, with the only adaptation being that the
 * `scope` partitioning is broader than the paper's {global, user, group} —
 * see ADR 0002. The algorithm itself does not change; scope is already part
 * of the nugget key κ, so different scopes naturally produce different keys
 * and never conflict.
 *
 * Pure function — does not touch storage. Returns a description of what
 * should change; the storage layer applies it transactionally.
 *
 * See ADR 0005, ADR 0002 and:
 *   "NuggetIndex: Governed Atomic Retrieval for Maintainable RAG"
 *   https://arxiv.org/html/2604.27306v1
 */

import { STATUS } from "../types.js";
import { RELATION_KIND, getRelationKind } from "../predicates.js";

/** Outcomes of conflict detection — informational, used in audit + UI. */
export const CONFLICT_OUTCOME = Object.freeze({
  NEW_KEY: "new_key",
  MERGED: "merged",
  SUCCESSION: "succession",
  MULTI_VALUED: "multi_valued",
  DEPRECATED_EXISTING: "deprecated_existing",
  DEPRECATED_NEW: "deprecated_new",
  CONTESTED: "contested",
});

/** Jaccard threshold for dedup — paper §3.3.2. */
const JACCARD_DEDUP_THRESHOLD = 0.85;

/** N-gram size for Jaccard character n-grams — paper uses character n-grams. */
const NGRAM_N = 3;

/**
 * Build the set of character n-grams from a string. Pads with sentinel
 * characters at the boundaries so short strings still produce stable grams.
 */
function characterNgrams(str, n = NGRAM_N) {
  const padded = `${"�".repeat(n - 1)}${String(str).toLowerCase()}${"".repeat(n - 1)}`;
  const out = new Set();
  for (let i = 0; i <= padded.length - n; i++) out.add(padded.slice(i, i + n));
  return out;
}

/**
 * Jaccard similarity between two strings via character n-grams.
 * Range [0, 1]. Identical strings → 1. Disjoint n-gram sets → 0.
 */
export function jaccardValue(a, b) {
  const A = characterNgrams(a);
  const B = characterNgrams(b);
  if (A.size === 0 && B.size === 0) return 1;
  let inter = 0;
  for (const t of A) if (B.has(t)) inter++;
  const union = A.size + B.size - inter;
  return union === 0 ? 0 : inter / union;
}

/**
 * Two half-open validity intervals overlap iff a.start < b.end AND b.start < a.end.
 * Null end means open-ended (+∞ per paper).
 */
export function intervalsOverlap(a, b) {
  const aEnd = a.end ?? Number.POSITIVE_INFINITY;
  const bEnd = b.end ?? Number.POSITIVE_INFINITY;
  return a.start < bEnd && b.start < aEnd;
}

/**
 * Count distinct provenance sources for a nugget. Used to evaluate "evidence ≥ 2"
 * branches of Algorithm 2.
 */
function evidenceCount(nugget) {
  if (!Array.isArray(nugget.provenance)) return 0;
  // Distinct by sourceUrl when present; otherwise count each entry.
  const seen = new Set();
  let unattributed = 0;
  for (const p of nugget.provenance) {
    if (p && p.sourceUrl) seen.add(p.sourceUrl);
    else unattributed++;
  }
  return seen.size + unattributed;
}

/**
 * Result schema:
 *   {
 *     outcome: keyof CONFLICT_OUTCOME,
 *     newStatus: keyof STATUS | null,        // status to assign to the candidate
 *                                            // null if candidate should be discarded (merged)
 *     mergeIntoId: string | null,            // when outcome=MERGED: existing nugget id
 *                                            // to merge the candidate's evidence into
 *     updates: Array<{ id, status?, validityEnd? }>  // edits to existing nuggets
 *   }
 */

/**
 * Run Algorithm 2 against a candidate and the set of existing nuggets that
 * share its key κ.
 *
 * @param {object} candidate  — proposed nugget (not yet inserted)
 * @param {Array<object>} sameKeyNuggets  — existing nuggets where computeKey(n) === computeKey(candidate)
 * @returns {object}  — see schema above
 */
export function detectConflict(candidate, sameKeyNuggets) {
  // (1)-(4) New key
  if (!sameKeyNuggets || sameKeyNuggets.length === 0) {
    return {
      outcome: CONFLICT_OUTCOME.NEW_KEY,
      newStatus: STATUS.ACTIVE,
      mergeIntoId: null,
      updates: [],
    };
  }

  // (5)-(7) Deduplication — Jaccard ≥ 0.85 on object value
  for (const existing of sameKeyNuggets) {
    if (jaccardValue(existing.fact.object, candidate.fact.object) >= JACCARD_DEDUP_THRESHOLD) {
      return {
        outcome: CONFLICT_OUTCOME.MERGED,
        newStatus: null,
        mergeIntoId: existing.id,
        updates: [],
      };
    }
  }

  // (8) Look up relation kind
  const relation = getRelationKind(candidate.fact.predicate);

  // (9) Find existing nuggets whose validity intervals overlap with the candidate
  const overlapping = sameKeyNuggets.filter((n) => intervalsOverlap(n.validity, candidate.validity));

  // (10)-(11) Non-overlapping OR multi-valued → succession / concurrent
  if (overlapping.length === 0 || relation === RELATION_KIND.MULTI_VALUED) {
    return {
      outcome: relation === RELATION_KIND.MULTI_VALUED ? CONFLICT_OUTCOME.MULTI_VALUED : CONFLICT_OUTCOME.SUCCESSION,
      newStatus: STATUS.ACTIVE,
      mergeIntoId: null,
      updates: [],
    };
  }

  // (12)-(18) Functional + overlap — apply per-existing decision rule
  const candidateEvidence = evidenceCount(candidate);
  const updates = [];
  let newStatus = STATUS.ACTIVE;
  let contestedAny = false;
  let deprecatedExistingAny = false;
  let deprecatedNewAny = false;

  for (const existing of overlapping) {
    const existingEvidence = evidenceCount(existing);
    if (candidateEvidence >= 2 && candidate.validity.start > existing.validity.start) {
      // Candidate wins: existing → Deprecated; tighten existing.validityEnd to candidate.validity.start
      updates.push({
        id: existing.id,
        status: STATUS.DEPRECATED,
        validityEnd: candidate.validity.start,
      });
      deprecatedExistingAny = true;
    } else if (existingEvidence >= 2 && existing.validity.start > candidate.validity.start) {
      // Existing wins: candidate → Deprecated; tighten candidate.validityEnd to existing.validity.start
      newStatus = STATUS.DEPRECATED;
      // We model this by tightening the candidate's own end; storage will pick it up
      // via the returned newStatus + the implied tightening.
      deprecatedNewAny = true;
      // Side effect on candidate (described, not mutated here); caller applies.
      // We surface the tightening through the result so the caller can apply it
      // before inserting the candidate.
      candidate.validity.end = Math.min(
        candidate.validity.end ?? Number.POSITIVE_INFINITY,
        existing.validity.start
      );
      if (!Number.isFinite(candidate.validity.end)) candidate.validity.end = null;
    } else {
      // Ambiguous → both Contested
      updates.push({ id: existing.id, status: STATUS.CONTESTED });
      newStatus = STATUS.CONTESTED;
      contestedAny = true;
    }
  }

  let outcome;
  if (contestedAny) outcome = CONFLICT_OUTCOME.CONTESTED;
  else if (deprecatedNewAny && !deprecatedExistingAny) outcome = CONFLICT_OUTCOME.DEPRECATED_NEW;
  else if (deprecatedExistingAny && !deprecatedNewAny) outcome = CONFLICT_OUTCOME.DEPRECATED_EXISTING;
  else if (deprecatedExistingAny && deprecatedNewAny) outcome = CONFLICT_OUTCOME.CONTESTED;
  else outcome = CONFLICT_OUTCOME.SUCCESSION;

  return {
    outcome,
    newStatus,
    mergeIntoId: null,
    updates,
  };
}
