/**
 * notifications.js — adapter from the Scheduler's NotificationSink contract
 * to chrome.notifications.
 *
 * Used for watcher firings ("price dropped below $500", "issue closed", …),
 * and reused by the task-event helpers for task complete / failed / paused
 * notifications.
 */

import browser from 'webextension-polyfill';

const DEFAULT_ICON = 'icons/icon-128.png';

let _notifyEnabled = true;

/** Toggle for headless tests; chrome.notifications is unavailable in the
 *  service-worker test harness. */
export function setNotificationsEnabled(enabled) {
  _notifyEnabled = !!enabled;
}

async function createNotification({ id, title, message, iconUrl }) {
  if (!_notifyEnabled) return null;
  if (!browser?.notifications?.create) return null;
  try {
    return await browser.notifications.create(id ?? '', {
      type: 'basic',
      iconUrl: iconUrl ?? DEFAULT_ICON,
      title: title ?? 'BrowserMemex',
      message: message ?? '',
      priority: 1,
    });
  } catch (e) {
    // eslint-disable-next-line no-console
    console.warn('[browser-memex] notification failed:', e?.message ?? e);
    return null;
  }
}

/**
 * Scheduler-side NotificationSink. The Scheduler calls `.notify(notif)` on
 * watcher firings; we map that to a desktop notification.
 */
export const schedulerNotificationSink = {
  async notify(notif) {
    const sampleSummary =
      typeof notif?.sample === 'object'
        ? JSON.stringify(notif.sample).slice(0, 120)
        : String(notif?.sample ?? '');
    await createNotification({
      id: `watcher-${notif?.taskId}-${notif?.firedAt ?? Date.now()}`,
      title: notif?.title ? `Watcher: ${notif.title}` : 'BrowserMemex watcher fired',
      message: notif?.description
        ? `${notif.description}\n${sampleSummary}`
        : sampleSummary || 'A watcher condition was met.',
    });
  },
};

/** Generic task-event notifications, fired from service-worker.js whenever
 *  a one-shot or scheduled task completes / fails / requires user input. */
export async function notifyTaskCompleted({ taskTitle, taskId }) {
  await createNotification({
    id: `task-done-${taskId ?? Date.now()}`,
    title: 'Task completed',
    message: taskTitle ?? '',
  });
}

export async function notifyTaskFailed({ taskTitle, taskId, error }) {
  await createNotification({
    id: `task-fail-${taskId ?? Date.now()}`,
    title: 'Task failed',
    message: `${taskTitle ?? ''}\n${error ?? ''}`.trim(),
  });
}

export async function notifyTaskNeedsInput({ taskTitle, taskId, question }) {
  await createNotification({
    id: `task-input-${taskId ?? Date.now()}`,
    title: 'Task needs input',
    message: `${taskTitle ?? ''}\n${question ?? ''}`.trim(),
  });
}
