/**
 * alarms-bridge.js — wires `chrome.alarms` to the Scheduler.
 *
 * The service worker is ephemeral (Chrome MV3 evicts it). Alarms are the
 * durable wake-up mechanism. We register one persistent alarm with a short
 * cadence; on each wake-up we tick the Scheduler, which pulls ready tasks
 * from the persistent SQLite store and drains them.
 *
 * Cadence rationale (see ADR 0006 + perf budgets):
 *   - Tick every 60 seconds when idle; quick enough that watchers feel
 *     responsive, slow enough not to thrash the service worker
 *   - The Scheduler itself controls per-task run scheduling; the alarm is
 *     just a heartbeat
 *
 * The bridge also re-arms the alarm immediately when a task is created
 * with `nextRunAt <= now` so user-initiated tasks don't wait up to a
 * minute to start.
 */

import browser from "webextension-polyfill";

const ALARM_NAME = "browser-memex-scheduler-tick";
const TICK_PERIOD_MINUTES = 1;

let scheduler = null;
let registered = false;

/**
 * Initialize the bridge with a configured Scheduler instance. Idempotent.
 *
 * @param {object} sched — Scheduler from @browser-memex/core/scheduler
 */
export async function startAlarmsBridge(sched) {
  if (!sched || typeof sched.tick !== "function") {
    throw new Error("startAlarmsBridge: scheduler with tick() required");
  }
  scheduler = sched;

  // Register the alarm if not already
  const existing = await browser.alarms.get(ALARM_NAME);
  if (!existing) {
    await browser.alarms.create(ALARM_NAME, {
      periodInMinutes: TICK_PERIOD_MINUTES,
      // First fire after the same cadence so we don't double-tick on install
      delayInMinutes: TICK_PERIOD_MINUTES,
    });
  }

  if (!registered) {
    browser.alarms.onAlarm.addListener(onAlarm);
    registered = true;
  }
}

/**
 * Trigger one tick immediately, regardless of the alarm cadence. Used when
 * the user creates a task that should run right away.
 */
export async function pokeScheduler() {
  if (!scheduler) return;
  await scheduler.tick(Date.now());
}

/**
 * Cancel the alarm. Used when the extension is being uninstalled or paused.
 */
export async function stopAlarmsBridge() {
  await browser.alarms.clear(ALARM_NAME);
  if (registered) {
    browser.alarms.onAlarm.removeListener(onAlarm);
    registered = false;
  }
  scheduler = null;
}

async function onAlarm(alarm) {
  if (alarm.name !== ALARM_NAME || !scheduler) return;
  try {
    await scheduler.tick(Date.now());
  } catch (err) {
    // Service worker swallows unhandled errors; surface to console for diagnostics.
    // eslint-disable-next-line no-console
    console.error("[browser-memex] scheduler tick failed:", err);
  }
}
