/**
 * Task memory: records outcomes and evolves domain skills from history.
 * No extra LLM calls — uses simple pattern extraction.
 */

import {
  addTaskRecord,
  getTasksByDomain,
  getLearnedSkill,
  putLearnedSkill,
  countTasksByDomain,
  pruneOldRecords,
} from './task-memory-db.js';

const EVOLVE_THRESHOLD = 3;
const MAX_HISTORY_IN_PROMPT = 5;
const MAX_SKILL_LENGTH = 800;

/**
 * Record a completed task outcome to IndexedDB.
 */
export async function recordTaskOutcome(logData, steps, tabUrl) {
  if (!tabUrl) return;

  let domain;
  try {
    domain = new URL(tabUrl).hostname.toLowerCase();
  } catch {
    return;
  }

  const toolsUsed = [...new Set((steps || []).map(s => s.tool).filter(Boolean))];

  const keyActions = (steps || [])
    .filter(s => s.status === 'executed' && s.tool)
    .slice(0, 20)
    .map(s => {
      const snippet = typeof s.input === 'string'
        ? s.input.substring(0, 80)
        : JSON.stringify(s.input || {}).substring(0, 80);
      return `${s.tool} -> ${snippet}`;
    })
    .slice(0, 5);

  const durationSec =
    logData.startTime && logData.endTime
      ? Math.round((new Date(logData.endTime) - new Date(logData.startTime)) / 1000)
      : 0;

  const record = {
    domain,
    task: (logData.task || '').substring(0, 500),
    status: logData.status === 'completed' ? 'completed' : 'failed',
    startTime: logData.startTime,
    endTime: logData.endTime,
    durationSec,
    toolsUsed,
    stepCount: (steps || []).length,
    apiCalls: logData.usage?.apiCalls || 0,
    inputTokens: logData.usage?.inputTokens || 0,
    outputTokens: logData.usage?.outputTokens || 0,
    errorSummary: logData.error ? logData.error.substring(0, 200) : null,
    keyActions,
    createdAt: new Date().toISOString(),
  };

  await addTaskRecord(record);

  // Evolve skill if enough history
  const count = await countTasksByDomain(domain);
  if (count >= EVOLVE_THRESHOLD) {
    await evolveSkill(domain);
  }

  // Periodic cleanup
  if (Math.random() < 0.1) {
    await pruneOldRecords(90);
  }
}

/**
 * Get task memory context for a domain to inject into the system prompt.
 */
export async function getTaskMemoryForDomain(url) {
  if (!url) return null;

  let domain;
  try {
    domain = new URL(url).hostname.toLowerCase();
  } catch {
    return null;
  }

  const recentTasks = await getTasksByDomain(domain, MAX_HISTORY_IN_PROMPT);
  const learned = await getLearnedSkill(domain);

  if (recentTasks.length === 0 && !learned) return null;

  const recentOutcomes = recentTasks.map(t => ({
    task: t.task,
    status: t.status,
    durationSec: t.durationSec,
    toolsUsed: t.toolsUsed,
    keyActions: t.keyActions,
    errorSummary: t.errorSummary,
  }));

  return {
    domain,
    recentOutcomes,
    learnedSkill: learned?.skill || null,
  };
}

/**
 * Generate a learned skill from accumulated task history.
 * Pure pattern extraction — no LLM cost.
 */
async function evolveSkill(domain) {
  const tasks = await getTasksByDomain(domain, 20);
  if (tasks.length < EVOLVE_THRESHOLD) return;

  const total = tasks.length;
  const successes = tasks.filter(t => t.status === 'completed').length;
  const successRate = `${successes}/${total}`;

  // Most common tools
  const toolFreq = {};
  for (const t of tasks) {
    for (const tool of t.toolsUsed || []) {
      toolFreq[tool] = (toolFreq[tool] || 0) + 1;
    }
  }
  const commonTools = Object.entries(toolFreq)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([name]) => name);

  // Common action patterns from successful tasks
  const successfulTasks = tasks.filter(t => t.status === 'completed');
  const actionFreq = {};
  for (const t of successfulTasks) {
    for (const action of t.keyActions || []) {
      actionFreq[action] = (actionFreq[action] || 0) + 1;
    }
  }
  const commonPatterns = Object.entries(actionFreq)
    .filter(([, count]) => count >= 2)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([pattern]) => pattern);

  // Error patterns from failed tasks
  const failedTasks = tasks.filter(t => t.status === 'failed' && t.errorSummary);
  const errorPatterns = [...new Set(failedTasks.map(t => t.errorSummary))].slice(0, 3);

  // Avg duration of successful tasks
  const avgDuration =
    successfulTasks.length > 0
      ? Math.round(successfulTasks.reduce((sum, t) => sum + t.durationSec, 0) / successfulTasks.length)
      : 0;

  // Build skill text
  let skill = `Learned from ${total} previous tasks (${successRate} succeeded):\n`;
  if (commonTools.length > 0) {
    skill += `- Common tools: ${commonTools.join(', ')}\n`;
  }
  if (commonPatterns.length > 0) {
    skill += `- Effective patterns:\n`;
    for (const p of commonPatterns) {
      skill += `  - ${p}\n`;
    }
  }
  if (errorPatterns.length > 0) {
    skill += `- Watch out for:\n`;
    for (const e of errorPatterns) {
      skill += `  - ${e}\n`;
    }
  }
  if (avgDuration > 0) {
    skill += `- Typical duration: ~${avgDuration}s\n`;
  }

  skill = skill.substring(0, MAX_SKILL_LENGTH);

  await putLearnedSkill({
    domain,
    skill,
    basedOnCount: total,
    lastUpdated: new Date().toISOString(),
    successRate,
    commonTools,
    commonPatterns,
  });
}
