/**
 * extension-services.js — single-point boot wiring for the @browser-memex/core
 * modules inside the service worker.
 *
 * Initializes in two stages:
 *
 *   bootProfiles()  — non-SQLite, always succeeds (chrome.storage only).
 *                     Used by the rail-avatar UI so the active profile is
 *                     available even if the heavier SQLite boot is still
 *                     loading or fails.
 *
 *   bootServices()  — full boot: SqliteStore + NuggetStore, TaskSqliteStore +
 *                     TaskStore, SkillSqliteStore + SkillStore,
 *                     AvailabilitySnapshot, AgentDispatcher, Scheduler,
 *                     chrome.alarms bridge. Requires WASM + a working VFS.
 *
 * Both are idempotent. Callers (the service worker, tool handlers, etc.)
 * ask for a service and get a working instance.
 */

import sqlite3InitModule from "@sqlite.org/sqlite-wasm";
import browser from "webextension-polyfill";
import { SqliteStore } from "@browser-memex/core/memory";
import { NuggetStore } from "@browser-memex/core/memory";
import { TaskSqliteStore, TaskStore, Scheduler } from "@browser-memex/core/scheduler";
import { SkillSqliteStore, SkillStore } from "@browser-memex/core/skills";
import { ProfileStore, makeBrowserStorageAdapter } from "@browser-memex/core/profiles";

import { AgentDispatcher } from "./agent-dispatcher.js";
import { AvailabilitySnapshot } from "./availability-snapshot.js";
import { startAlarmsBridge, pokeScheduler } from "./alarms-bridge.js";
import { schedulerNotificationSink } from "./notifications.js";

const DB_NUGGETS = "browser-memex-webnugget.sqlite3";
const DB_TASKS = "browser-memex-tasks.sqlite3";
const DB_SKILLS = "browser-memex-skills.sqlite3";

let _profileStore = null;
let _activeProfileId = null;
let _profilesInitPromise = null;

let _state = null;
let _initPromise = null;

/**
 * Stage 1: ProfileStore boot. Runs before any SQLite work so the rail-avatar
 * UI always has a profile to render, even if SQLite/WASM is unavailable.
 *
 * Returns { profileStore, activeProfileId }.
 */
export function bootProfiles() {
  if (_profileStore && _activeProfileId) {
    return Promise.resolve({ profileStore: _profileStore, activeProfileId: _activeProfileId });
  }
  if (_profilesInitPromise) return _profilesInitPromise;

  _profilesInitPromise = (async () => {
    _profileStore = new ProfileStore({ storage: makeBrowserStorageAdapter(browser) });
    const active = await _profileStore.getActive(Date.now());
    _activeProfileId = active.id;
    return { profileStore: _profileStore, activeProfileId: _activeProfileId };
  })().catch((e) => {
    _profilesInitPromise = null;
    throw e;
  });

  return _profilesInitPromise;
}

/**
 * Stage 2: full SQLite + scheduler + dispatcher boot. Requires profiles to be
 * booted first so the active profile is known.
 *
 * @param {object} opts
 * @param {object} opts.policy
 * @param {() => Promise<object>} opts.fetchAgentDetection
 * @param {(task: object) => Promise<object>} opts.runBrowserAgent
 * @param {object} [opts.llmClient]
 * @param {object} [opts.retry]
 * @param {('opfs-sahpool'|'opfs'|'memory')} [opts.vfs='opfs-sahpool']
 */
export function bootServices(opts) {
  if (_state) return Promise.resolve(_state);
  if (_initPromise) return _initPromise;

  _initPromise = (async () => {
    if (!opts || !opts.policy || !opts.fetchAgentDetection || !opts.runBrowserAgent) {
      throw new Error("bootServices: policy + fetchAgentDetection + runBrowserAgent are required");
    }

    // Ensure profiles are booted first; the active profile id is needed for
    // scoping all reads/writes.
    const { profileStore } = await bootProfiles();

    // VFS selection. `opfs-sahpool` requires FileSystemSyncAccessHandle, which
    // is only available in worker contexts. Chrome MV3 service workers expose
    // it; Firefox MV3 event-page backgrounds do not. Callers pass `vfs`
    // explicitly, with `opfs-sahpool` as default and `memory` as a graceful
    // fallback.
    const vfs = opts.vfs ?? "opfs-sahpool";

    const nuggetStore = new NuggetStore({
      storage: new SqliteStore({
        initModule: sqlite3InitModule,
        vfs,
        path: vfs === "memory" ? undefined : DB_NUGGETS,
      }),
    });
    await nuggetStore.open();

    const taskStore = new TaskStore({
      storage: new TaskSqliteStore({
        initModule: sqlite3InitModule,
        vfs,
        path: vfs === "memory" ? undefined : DB_TASKS,
      }),
    });
    await taskStore.open();

    const skillStore = new SkillStore({
      storage: new SkillSqliteStore({
        initModule: sqlite3InitModule,
        vfs,
        path: vfs === "memory" ? undefined : DB_SKILLS,
      }),
    });
    await skillStore.open();

    const availability = new AvailabilitySnapshot({
      fetchFromMcp: opts.fetchAgentDetection,
    });

    const dispatcher = new AgentDispatcher(
      {
        availability: () => availability.get(),
        policy: opts.policy,
        runBrowserAgent: opts.runBrowserAgent,
      },
      { llmClient: opts.llmClient }
    );

    const scheduler = new Scheduler({
      taskStore,
      dispatcher,
      retry: opts.retry,
      notifications: schedulerNotificationSink,
    });

    await startAlarmsBridge(scheduler);

    _state = {
      nuggetStore,
      taskStore,
      skillStore,
      profileStore,
      availability,
      dispatcher,
      scheduler,
      vfs,
    };
    return _state;
  })().catch((e) => {
    _initPromise = null;
    throw e;
  });

  return _initPromise;
}

/** Whether bootServices has completed successfully. */
export function isBooted() {
  return _state !== null;
}

/** Whether bootProfiles has completed successfully. */
export function isProfilesBooted() {
  return _profileStore !== null && _activeProfileId !== null;
}

/**
 * Get the current active profile id. Reads from the cached value updated by
 * setActiveProfile(). Returns null if profiles haven't booted yet.
 */
export function activeProfileId() {
  return _activeProfileId;
}

/**
 * Atomically switch the active profile. Persists to chrome.storage via
 * ProfileStore.setActive and updates the in-memory cache used by RPC
 * scoping. Returns the new active profile id.
 */
export async function setActiveProfile(id) {
  if (!_profileStore) {
    await bootProfiles();
  }
  await _profileStore.setActive(id);
  _activeProfileId = id;
  return id;
}

/**
 * Convenience: schedule a task and immediately poke the scheduler so it
 * doesn't wait for the next alarm tick. Used by the side panel's
 * "Create task" flow.
 */
export async function scheduleAndRun(taskSpec) {
  const { taskStore } = await bootServices(arguments[1] ?? {});
  const created = taskStore.create(taskSpec, Date.now(), _activeProfileId);
  await pokeScheduler();
  return created;
}

/** Direct accessor; throws if bootServices hasn't completed. */
export function services() {
  if (!_state) throw new Error("services(): bootServices() not yet called");
  return _state;
}

/**
 * Run a skill end-to-end. Loads the workflow engine lazily so we don't pay
 * the import cost on every boot. Used by both the side-panel popup ("Run
 * now" button) and the cross-agent memex bridge (`memex_skills_run`).
 */
export async function runSkill(skillId, inputs = {}) {
  if (!_state) throw new Error("runSkill: bootServices() not yet called");
  const { WorkflowEngine } = await import("@browser-memex/core/workflows");
  const skill = _state.skillStore.get(skillId);
  if (!skill) throw new Error(`runSkill: skill '${skillId}' not found`);
  if (skill.profileId !== _activeProfileId) {
    throw new Error(`runSkill: skill belongs to a different profile`);
  }
  const dispatcher = {
    dispatchTask: async (task, ctx) => _state.dispatcher.dispatch(task, ctx),
    dispatchAction: async () => ({ success: false, error: "RUN_ACTION not yet implemented" }),
  };
  const engine = new WorkflowEngine({ dispatcher });
  const result = await engine.run(skill.steps, inputs, Date.now());
  try {
    _state.skillStore.recordRun(
      skillId,
      {
        startedAt: Date.now(),
        endedAt: Date.now(),
        status: result.success ? "success" : "failure",
        inputs,
        outputs: result.context?.stageOutputs,
        error: result.error,
      },
      Date.now()
    );
  } catch {
    /* non-fatal */
  }
  return result;
}
